pub fn pin(&mut self, by: impl Into<String>) {
        let by = by.into();
        debug_assert!(!by.is_empty(), "pin `by` must not be empty");
        self.pin = Some(PinInfo {
            by,
            at: Utc::now(),
        });
    }
pub fn unpin(&mut self) {
        self.pin = None;
    }
pub fn is_pinned(&self) -> bool {
        self.pin.is_some()
    }
